========================================================================== */

/* =========================================
   Component Styles
   ========================================= */

.post .package_parts {

	/* l-section */

	.l-section {
		font-family: var(--body-font-family);
		font-weight: 400;
		color: var(--color-font);

		&.l-section--bgcolor01 {
			background-color: var(--color-primary);
		}

		&.l-section--bgcolor02 {
			background-color: var(--color-primary-tint);
		}

		&.l-section--bgcolor03 {
			background-color: var(--color-secondary);
		}

		&.l-section--bgcolor-half {
			.l-section__wrap {

				position: relative;

				&::before {
					content: '';
					position: absolute;
					bottom: 0;
					left: 0;
					width: 100%;
					height: 50%;
					background-color: var(--color-primary);
					z-index: -1;
				}
			}
		}

		&.l-section--bgimg {
			background: url('https: //picsum.photos/id/10/800/533') no-repeat center center;
			background-size: cover;
		}

		&.l-section--bgimg-parallax {
			position: relative;
			width: 100%;
			clip-path: inset(0);

			&::before {
				content: "";
				position: fixed;
				top: 0;
				left: 0;
				width: 100%;
				height: 100%;
				z-index: -1;
				background: url('https://picsum.photos/id/10/800/533') no-repeat center center;
				background-size: cover;
				pointer-events: none;
			}
		}

		&.l-section--bgimg-half {
			.l-section__wrap {
				position: relative;

				&::before {
					content: '';
					position: absolute;
					bottom: 0;
					left: 0;
					width: 100%;
					height: 50%;
					background: url('https://picsum.photos/id/10/800/533') no-repeat center center;
					background-size: cover;
					z-index: -1;
				}
			}
		}

		&.l-section--bgimg-halfparallax {
			.l-section__wrap {
				position: relative;
			}

			.l-section__parallax-area {
				position: absolute;
				bottom: 0;
				left: 0;
				width: 100%;
				height: 50%;
				clip-path: inset(0);

				&::before {
					content: "";
					position: fixed;
					border-bottom-width: 0;
					left: 0;
					bottom: 0;
					width: 100%;
					height: 100%;
					z-index: -1;
					background: url('https://picsum.photos/id/10/800/533') no-repeat center center;
					background-size: cover;
					pointer-events: none;
				}
			}
		}
	}

	/* c-title */

	.c-title {
		background-color: var(--color-font);
		padding: var(--px60) var(--px20) var(--px80);
	}

	.c-title__txt {
		line-height: 1;
		display: flex;
		gap: var(--px12);
		flex-direction: column;
		align-items: center;
		text-align: center;
		margin: 0 auto;
		max-width: 1100px;
	}

	.c-title__en {
		font-family: var(--font-family02);
		font-size: var(--px14);
		font-weight: 400;
		color: var(--color-primary);
		display: block;
		width: fit-content;
		padding: 8px;
		min-width: var(--px80);
		border-radius: var(--px40);
		background-color: #fff;
	}

	.c-title__ja {
		font-family: var(--body-font-family);
		font-size: var(--px50);
		font-weight: 700;
		color: #fff;
		line-height: 1.4;
		letter-spacing: 0.1em;
	}

	.l-section__inner {
		max-width: var(--content-max-width);
		margin: 0 auto;
	}

	.l-section__wrap {
		padding: var(--px80) var(--px20);
	}
}

